using System; using System.Runtime.InteropServices; public class CredReader { [StructLayout(LayoutKind.Sequential, CharSet = CharSet.Unicode)] public struct CREDENTIAL { public uint flags; public uint type; public IntPtr targetName; public IntPtr comment; public System.Runtime.InteropServices.ComTypes.FILETIME lastWritten; public uint credentialBlobSize; public IntPtr credentialBlob; public uint persist; public uint attributeCount; public IntPtr attributes; public IntPtr targetAlias; public IntPtr userName; } [DllImport("advapi32.dll", EntryPoint = "CredReadW", CharSet = CharSet.Unicode, SetLastError = true)] public static extern bool CredRead(string target, int type, int reservedFlag, out IntPtr credentialPtr); [DllImport("advapi32.dll", SetLastError = true)] public static extern bool CredFree([In] IntPtr buffer); public static void Main(string[] args) { IntPtr credPtr; if (CredRead("gemini:antigravity", 1, 0, out credPtr)) { CREDENTIAL cred = (CREDENTIAL)Marshal.PtrToStructure(credPtr, typeof(CREDENTIAL)); Console.WriteLine("Target: " + Marshal.PtrToStringUni(cred.targetName)); Console.WriteLine("User: " + Marshal.PtrToStringUni(cred.userName)); Console.WriteLine("BlobSize: " + cred.credentialBlobSize); if (cred.credentialBlobSize > 0) { byte[] blob = new byte[cred.credentialBlobSize]; Marshal.Copy(cred.credentialBlob, blob, 0, (int)cred.credentialBlobSize); Console.WriteLine("Payload: " + System.Text.Encoding.UTF8.GetString(blob)); } CredFree(credPtr); } else { Console.WriteLine("ERROR: " + Marshal.GetLastWin32Error()); } } }
